selector_to_html = {"a[href=\"#request-mode\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">\u0420\u0435\u0436\u0438\u043c \u0437\u0430\u043f\u0440\u043e\u0441\u0430<a class=\"headerlink\" href=\"#request-mode\" title=\"\u0421\u0441\u044b\u043b\u043a\u0430 \u043d\u0430 \u044d\u0442\u043e\u0442 \u0437\u0430\u0433\u043e\u043b\u043e\u0432\u043e\u043a\">#</a></h3>", "a[href=\"#set-the-data-format-sent-by-the-scanner\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">\u0423\u0441\u0442\u0430\u043d\u043e\u0432\u0438\u0442\u044c \u0444\u043e\u0440\u043c\u0430\u0442 \u0434\u0430\u043d\u043d\u044b\u0445, \u043e\u0442\u043f\u0440\u0430\u0432\u043b\u0435\u043d\u043d\u044b\u0439 \u0441\u043a\u0430\u043d\u0435\u0440\u043e\u043c<a class=\"headerlink\" href=\"#set-the-data-format-sent-by-the-scanner\" title=\"\u0421\u0441\u044b\u043b\u043a\u0430 \u043d\u0430 \u044d\u0442\u043e\u0442 \u0437\u0430\u0433\u043e\u043b\u043e\u0432\u043e\u043a\">#</a></h3>", "a[href=\"#id3\"]": "<figure class=\"align-center\" id=\"id3\">\n<a class=\"reference internal image-reference\" href=\"../../media/25WFCOMMPM23S1.png\"><img alt=\"../../media/25WFCOMMPM23S1.png\" src=\"../../media/25WFCOMMPM23S1.png\" style=\"width: 300px;\"/>\n</a>\n<figcaption>\n<p><span class=\"caption-text\">Json Format</span><a class=\"headerlink\" href=\"#id3\" title=\"\u0421\u0441\u044b\u043b\u043a\u0430 \u043d\u0430 \u044d\u0442\u043e \u0438\u0437\u043e\u0431\u0440\u0430\u0436\u0435\u043d\u0438\u0435\">#</a></p>\n</figcaption>\n</figure>", "a[href=\"wireless.html#data-rceiving-format\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">\u0424\u043e\u0440\u043c\u0430\u0442 \u0432\u043e\u0441\u0441\u0442\u0430\u043d\u043e\u0432\u043b\u0435\u043d\u0438\u044f \u0434\u0430\u043d\u043d\u044b\u0445<a class=\"headerlink\" href=\"#data-rceiving-format\" title=\"\u0421\u0441\u044b\u043b\u043a\u0430 \u043d\u0430 \u044d\u0442\u043e\u0442 \u0437\u0430\u0433\u043e\u043b\u043e\u0432\u043e\u043a\">#</a></h2><h3>\u0413\u043e\u043b\u043e\u0441\u043e\u0432\u043e\u0439 \u043a\u043e\u0434<a class=\"headerlink\" href=\"#voice-code\" title=\"\u0421\u0441\u044b\u043b\u043a\u0430 \u043d\u0430 \u044d\u0442\u043e\u0442 \u0437\u0430\u0433\u043e\u043b\u043e\u0432\u043e\u043a\">#</a></h3>", "a[href=\"#request-url\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">URL \u0437\u0430\u043f\u0440\u043e\u0441\u0430<a class=\"headerlink\" href=\"#request-url\" title=\"\u0421\u0441\u044b\u043b\u043a\u0430 \u043d\u0430 \u044d\u0442\u043e\u0442 \u0437\u0430\u0433\u043e\u043b\u043e\u0432\u043e\u043a\">#</a></h3>", "a[href=\"#use-http-protocol-to-transfer-data\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\">\u0418\u0441\u043f\u043e\u043b\u044c\u0437\u043e\u0432\u0430\u0442\u044c HTTP \u043f\u0440\u043e\u0442\u043e\u043a\u043e\u043b \u0434\u043b\u044f \u043f\u0435\u0440\u0435\u0434\u0430\u0447\u0438 \u0434\u0430\u043d\u043d\u044b\u0445<a class=\"headerlink\" href=\"#use-http-protocol-to-transfer-data\" title=\"\u0421\u0441\u044b\u043b\u043a\u0430 \u043d\u0430 \u044d\u0442\u043e\u0442 \u0437\u0430\u0433\u043e\u043b\u043e\u0432\u043e\u043a\">#</a></h1><h2>\u0421\u043e\u0437\u0434\u0430\u0442\u044c REST API<a class=\"headerlink\" href=\"#create-rest-api\" title=\"\u0421\u0441\u044b\u043b\u043a\u0430 \u043d\u0430 \u044d\u0442\u043e\u0442 \u0437\u0430\u0433\u043e\u043b\u043e\u0432\u043e\u043a\">#</a></h2><h3>\u041a\u0440\u0430\u0442\u043a\u043e\u0435 \u043e\u043f\u0438\u0441\u0430\u043d\u0438\u0435<a class=\"headerlink\" href=\"#brief-description\" title=\"\u0421\u0441\u044b\u043b\u043a\u0430 \u043d\u0430 \u044d\u0442\u043e\u0442 \u0437\u0430\u0433\u043e\u043b\u043e\u0432\u043e\u043a\">#</a></h3>", "a[href=\"#id1\"]": "<div class=\"literal-block-wrapper docutils container\" id=\"id1\">\n<div class=\"code-block-caption\"><span class=\"caption-text\">\u041f\u0440\u0438\u043c\u0435\u0440 \u0437\u0430\u043f\u0440\u043e\u0441\u0430</span><a class=\"headerlink\" href=\"#id1\" title=\"\u0421\u0441\u044b\u043b\u043a\u0430 \u043d\u0430 \u044d\u0442\u043e\u0442 \u043a\u043e\u0434\">#</a></div>\n<div class=\"highlight-json notranslate\"><div class=\"highlight\"><pre><span></span><span class=\"linenos\">1</span><span class=\"p\">{</span><span class=\"nt\">\"id\"</span><span class=\"p\">:</span><span class=\"w\"> </span><span class=\"s2\">\"04B9023A\"</span><span class=\"p\">,</span><span class=\"nt\">\"msg\"</span><span class=\"p\">:</span><span class=\"s2\">\"1234567890\"</span><span class=\"p\">}</span>\n</pre></div>\n</div>\n</div>", "a[href=\"#brief-description\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">\u041a\u0440\u0430\u0442\u043a\u043e\u0435 \u043e\u043f\u0438\u0441\u0430\u043d\u0438\u0435<a class=\"headerlink\" href=\"#brief-description\" title=\"\u0421\u0441\u044b\u043b\u043a\u0430 \u043d\u0430 \u044d\u0442\u043e\u0442 \u0437\u0430\u0433\u043e\u043b\u043e\u0432\u043e\u043a\">#</a></h3>", "a[href=\"#configure-wifi-and-api-url-address\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">\u041d\u0430\u0441\u0442\u0440\u043e\u0438\u0442\u044c WiFi \u0438 API URL \u0430\u0434\u0440\u0435\u0441<a class=\"headerlink\" href=\"#configure-wifi-and-api-url-address\" title=\"\u0421\u0441\u044b\u043b\u043a\u0430 \u043d\u0430 \u044d\u0442\u043e\u0442 \u0437\u0430\u0433\u043e\u043b\u043e\u0432\u043e\u043a\">#</a></h3>", "a[href=\"#create-rest-api\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">\u0421\u043e\u0437\u0434\u0430\u0442\u044c REST API<a class=\"headerlink\" href=\"#create-rest-api\" title=\"\u0421\u0441\u044b\u043b\u043a\u0430 \u043d\u0430 \u044d\u0442\u043e\u0442 \u0437\u0430\u0433\u043e\u043b\u043e\u0432\u043e\u043a\">#</a></h2><h3>\u041a\u0440\u0430\u0442\u043a\u043e\u0435 \u043e\u043f\u0438\u0441\u0430\u043d\u0438\u0435<a class=\"headerlink\" href=\"#brief-description\" title=\"\u0421\u0441\u044b\u043b\u043a\u0430 \u043d\u0430 \u044d\u0442\u043e\u0442 \u0437\u0430\u0433\u043e\u043b\u043e\u0432\u043e\u043a\">#</a></h3>", "a[href=\"#return-parameter\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">\u041f\u0430\u0440\u0430\u043c\u0435\u0442\u0440 \u0432\u043e\u0437\u0432\u0440\u0430\u0442\u0430<a class=\"headerlink\" href=\"#return-parameter\" title=\"\u0421\u0441\u044b\u043b\u043a\u0430 \u043d\u0430 \u044d\u0442\u043e\u0442 \u0437\u0430\u0433\u043e\u043b\u043e\u0432\u043e\u043a\">#</a></h3><p>\u041f\u043e\u0434\u0440\u043e\u0431\u043d\u0435\u0435 \u0441\u043c. <a class=\"reference internal\" href=\"wireless.html#data-rceiving-format\"><span class=\"std std-ref\">\u0424\u043e\u0440\u043c\u0430\u0442 \u043f\u0440\u0438\u0435\u043c\u0430 \u0434\u0430\u043d\u043d\u044b\u0445</span></a></p>", "a[href=\"#request-parameters\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">\u041f\u0430\u0440\u0430\u043c\u0435\u0442\u0440\u044b \u0437\u0430\u043f\u0440\u043e\u0441\u0430<a class=\"headerlink\" href=\"#request-parameters\" title=\"\u0421\u0441\u044b\u043b\u043a\u0430 \u043d\u0430 \u044d\u0442\u043e\u0442 \u0437\u0430\u0433\u043e\u043b\u043e\u0432\u043e\u043a\">#</a></h3>", "a[href=\"#configure-scanner\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">\u041d\u0430\u0441\u0442\u0440\u043e\u0438\u0442\u044c \u0441\u043a\u0430\u043d\u0435\u0440<a class=\"headerlink\" href=\"#configure-scanner\" title=\"\u0421\u0441\u044b\u043b\u043a\u0430 \u043d\u0430 \u044d\u0442\u043e\u0442 \u0437\u0430\u0433\u043e\u043b\u043e\u0432\u043e\u043a\">#</a></h2><h3>\u0423\u0441\u0442\u0430\u043d\u043e\u0432\u0438\u0442\u044c \u0442\u0438\u043f \u0441\u043e\u0434\u0435\u0440\u0436\u0438\u043c\u043e\u0433\u043e \u0437\u0430\u043f\u0440\u043e\u0441\u0430 \u0441\u043a\u0430\u043d\u0435\u0440\u0430<a class=\"headerlink\" href=\"#set-the-content-type-of-the-scanner-request\" title=\"\u0421\u0441\u044b\u043b\u043a\u0430 \u043d\u0430 \u044d\u0442\u043e\u0442 \u0437\u0430\u0433\u043e\u043b\u043e\u0432\u043e\u043a\">#</a></h3>", "a[href=\"#set-the-content-type-of-the-scanner-request\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">\u0423\u0441\u0442\u0430\u043d\u043e\u0432\u0438\u0442\u044c \u0442\u0438\u043f \u0441\u043e\u0434\u0435\u0440\u0436\u0438\u043c\u043e\u0433\u043e \u0437\u0430\u043f\u0440\u043e\u0441\u0430 \u0441\u043a\u0430\u043d\u0435\u0440\u0430<a class=\"headerlink\" href=\"#set-the-content-type-of-the-scanner-request\" title=\"\u0421\u0441\u044b\u043b\u043a\u0430 \u043d\u0430 \u044d\u0442\u043e\u0442 \u0437\u0430\u0433\u043e\u043b\u043e\u0432\u043e\u043a\">#</a></h3>", "a[href=\"#id2\"]": "<figure class=\"align-center\" id=\"id2\">\n<a class=\"reference internal image-reference\" href=\"../../media/application-json.png\"><img alt=\"../../media/application-json.png\" src=\"../../media/application-json.png\" style=\"width: 300px;\"/>\n</a>\n<figcaption>\n<p><span class=\"caption-text\">\u041f\u0440\u0438\u043b\u043e\u0436\u0435\u043d\u0438\u0435/Json</span><a class=\"headerlink\" href=\"#id2\" title=\"\u0421\u0441\u044b\u043b\u043a\u0430 \u043d\u0430 \u044d\u0442\u043e \u0438\u0437\u043e\u0431\u0440\u0430\u0436\u0435\u043d\u0438\u0435\">#</a></p>\n</figcaption>\n</figure>"}
skip_classes = ["headerlink", "sd-stretched-link", "sd-rounded-pill"]

window.onload = function () {
    for (const [select, tip_html] of Object.entries(selector_to_html)) {
        const links = document.querySelectorAll(`article.bd-article ${select}`);
        for (const link of links) {
            if (skip_classes.some(c => link.classList.contains(c))) {
                continue;
            }

            tippy(link, {
                content: tip_html,
                allowHTML: true,
                arrow: true,
                placement: 'auto-start', maxWidth: 500, interactive: false,

            });
        };
    };
    console.log("tippy tips loaded!");
};
